#include<bits/stdc++.h>
using namespace std;
struct node
{
    long long x,y,id,type,p;
    bool operator<(const node&b)const
    {
        if(y!=b.y)
        {
            return y<b.y;
        }
        return type<b.type;
    }
}a[2500010];
long long sum[2000010],ans[500010];
long long lowbit(long long x)
{
    return x&-x;
}
long long query(long long x)
{
    long long ans=0;
    for(long long i=x;i>=1;i-=lowbit(i))
    {
        ans+=sum[i];
    }
    return ans;
}
void update(long long x,long long v)
{
    for(long long i=x;i<=2000000;i+=lowbit(i))
    {
        sum[i]+=v;
    }
}
set<long long> v;
map<long long,long long> mp;
int main()
{
    long long n,m,k=0;
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=n;i++)
    {
        long long x,y,p;
        scanf("%lld%lld%lld",&x,&y,&p);
        a[++k].x=x;
        a[k].y=y;
        a[k].type=0;
        a[k].p=p;
        v.insert(x);
    }
    for(long long i=1;i<=m;i++)
    {
        long long ax,ay,bx,by;
        scanf("%lld%lld%lld%lld",&ax,&ay,&bx,&by);
        v.insert(ax-1);
        v.insert(ax);
        v.insert(bx);
        a[++k]=(node){bx,by,i,1,1};
        a[++k]=(node){ax-1,by,i,1,-1};
        a[++k]=(node){bx,ay-1,i,1,-1};
        a[++k]=(node){ax-1,ay-1,i,1,1};
    }
    sort(a+1,a+1+k);
    long long cnt=0;
    for(long long i:v)
    {
        cnt++;
        mp[i]=cnt;
    }
    for(long long i=1;i<=k;i++)
    {
        a[i].x=mp[a[i].x];
    }
    for(long long i=1;i<=k;i++)
    {
        // printf("a[%lld]=(node){%lld,%lld,%lld,%lld,%lld}\n",i,a[i].x,a[i].y,a[i].id,a[i].type,a[i].p);
        if(a[i].type==0)
        {
            update(a[i].x,a[i].p);
        }
        else
        {
            ans[a[i].id]+=query(a[i].x)*a[i].p;
        }
    }
    for(long long i=1;i<=m;i++)
    {
        printf("%lld\n",ans[i]);
    }
    return 0;
}
